-- Repartidor de misiones
lang["#MISSION_GIVER_CHALLENGER"] = "Xanthan"
lang["#MISSION_GIVER_CHALLENGER_SUBTITLE"] = "Desafiante del Yermo"
lang["#MISSION_GIVER_CHALLENGER_GREET_NEW"] = "Oye, ¿te consideras un verdadero habitante del yermo? Creo que demasiadas personas subestiman lo que significa serlo. Me llamo Xanthan, o como a la mayoría les gusta llamarme, 'el Desafiante'. Si realmente quieres demostrar tu valía a la gente de aquí y a mí, tengo algunas cosas que quiero que hagas. Solo ten en cuenta que no será fácil y también te pagarán muy bien por ello.\n\n\nAquí tienes algunos desafíos en los que puedes participar."
lang["#MISSION_GIVER_CHALLENGER_GREET"] = "Hola de nuevo, $playername. Si todavía buscas hacer desafíos, debería tener muchos disponibles.\n\n\nAquí tienes una lista de los que aún no has completado."
lang["#MISSION_GIVER_CHALLENGER_GREET_FINISHED"] = "¿Qué más puedo decir? Ya te has demostrado a mí y probablemente a muchas otras personas. No tengo nada disponible para ti en este momento."

-- Misiones
-- Utilidad
lang["#MISSION_CHALLENGER_LOOTINGTHEASH"] = "Saqueando la Ceniza"
lang["#MISSION_CHALLENGER_LOOTINGTHEASH_DESC"] = "¿Listo para un desafío? Este es bastante simple. Quiero que saquees todo lo que puedas, recolecta cada objeto por aquí. Cuando sientas que has hecho eso, vuelve a mí."
lang["#MISSION_CHALLENGER_LOOTINGTHEASH_HINT"] = "Saquéa contenedores en las Tierras de Ceniza. Puedes buscar dentro de pueblos, edificios y otras ubicaciones varias para encontrar contenedores."
lang["#MISSION_CHALLENGER_LOOTINGTHEASH_COMPLETE"] = "¿Saqueaste demasiados?"

lang["#MISSION_CHALLENGER_CULTIVATION"] = "Cultivo"
lang["#MISSION_CHALLENGER_CULTIVATION_DESC"] = "Sabes dónde recolectar plantas, ¿verdad? Bueno, para este desafío, quiero que vayas por esta área y empieces a cosechar tantas plantas como veas. Lo que hagas con ellas no me importa, pero mientras las recolectes, está bien."
lang["#MISSION_CHALLENGER_CULTIVATION_HINT"] = "Cosecha cualquier tipo de plantas. Las plantas suelen crecer en espacios abiertos a lo largo del yermo. Busca cerca de rocas y otras estructuras. También se pueden encontrar cerca de áreas con vegetación."
lang["#MISSION_CHALLENGER_CULTIVATION_COMPLETE"] = "¿Dónde demonios encuentras todas las buenas plantas?"

lang["#MISSION_CHALLENGER_BROKENSTEEL"] = "Acero Roto"
lang["#MISSION_CHALLENGER_BROKENSTEEL_DESC"] = "Estoy bastante seguro de que conoces los vehículos de por aquí. Están todos rotos, pero se pueden recuperar. Este desafío puede llevar algo de tiempo, pero quiero que lo hagas."
lang["#MISSION_CHALLENGER_BROKENSTEEL_HINT"] = "Recupera por completo vehículos. Puedes descomponer vehículos atacándolos con tus manos o con un arma cuerpo a cuerpo contundente. Las llaves inglesas y las palancas son generalmente buenas para recuperar. Los vehículos recuperables se pueden encontrar en o cerca de las carreteras."
lang["#MISSION_CHALLENGER_BROKENSTEEL_COMPLETE"] = "Haz lo que quieras con la chatarra, es tuya, no mía."

lang["#MISSION_CHALLENGER_RECYCLER"] = "Reciclador"
lang["#MISSION_CHALLENGER_RECYCLER_DESC"] = "Para este desafío, bastante simple. Necesito que descompongas basura que hayas saqueado en un banco de trabajo. No importa lo que sea, pero si lo estás descomponiendo, está bien."
lang["#MISSION_CHALLENGER_RECYCLER_HINT"] = "Descompón objetos. Puedes descomponer objetos en bancos de trabajo. Los bancos de trabajo generalmente se encuentran en pueblos, y a veces se pueden encontrar en áreas recónditas. Solo ciertos objetos se pueden descomponer, como latas de hojalata y portapapeles."
lang["#MISSION_CHALLENGER_RECYCLER_COMPLETE"] = "Será mejor que esperes no haber descompuesto algo que necesitabas."
lang["#MISSION_CHALLENGER_RECYCLER_INFO"] = "Descompón $amount objetos."

lang["#MISSION_CHALLENGER_WASTELANDFARMER"] = "Granjero del Yermo"
lang["#MISSION_CHALLENGER_WASTELANDFARMER_DESC"] = "Oye, entonces, eh, puede que quieras abastecerte y ponerte guantes. Tienes mucho trabajo por hacer. ¡Valdrá la pena, lo prometo!"
lang["#MISSION_CHALLENGER_WASTELANDFARMER_HINT"] = "Recupera por completo vehículos. Puedes descomponer vehículos atacándolos con tus manos o con un arma cuerpo a cuerpo contundente. Las llaves inglesas y las palancas son generalmente buenas para recuperar. Los vehículos recuperables se pueden encontrar en o cerca de las carreteras."
lang["#MISSION_CHALLENGER_WASTELANDFARMER_COMPLETE"] = "Dios mío, eres rápido. ¿Valió la pena?"

-- Combate
lang["#MISSION_CHALLENGER_GHOULHUNTER"] = "Cazador de Necrófagos"
lang["#MISSION_CHALLENGER_GHOULHUNTER_DESC"] = "Hay muchos necrófagos por aquí, generalmente escondidos en los lugares más recónditos. Para este desafío, necesito que los envíes a su tumba."
lang["#MISSION_CHALLENGER_GHOULHUNTER_HINT"] = "Elimina cualquier tipo de Necrófago Salvaje. Los necrófagos salvajes se pueden encontrar comúnmente en ubicaciones abandonadas."
lang["#MISSION_CHALLENGER_GHOULHUNTER_COMPLETE"] = "No más necrófagos salvajes merodeando, al menos de nuestra parte."

lang["#MISSION_CHALLENGER_CREEPYCRAWLERS"] = "Bichos Espeluznantes"
lang["#MISSION_CHALLENGER_CREEPYCRAWLERS_DESC"] = "Ugh, odio las Hormigas. Siempre me hacen sentir incómodo. Aquí tienes tu desafío, aplasta cualquier insecto gigante que encuentres."
lang["#MISSION_CHALLENGER_CREEPYCRAWLERS_HINT"] = "Elimina cualquier tipo de Hormiga Gigante. Las hormigas suelen aparecer en bosques y cuevas. Se recomienda enfrentarlas con armas de fuego."
lang["#MISSION_CHALLENGER_CREEPYCRAWLERS_COMPLETE"] = "Bleh, las Hormigas apestan."

lang["#MISSION_CHALLENGER_SHREDDEDSCALES"] = "Escamas Trituradas"
lang["#MISSION_CHALLENGER_SHREDDEDSCALES_DESC"] = "¿Te gusta cazar? Los Geckos suelen ser animales buenos para cazar en el yermo. Desafortunadamente, o afortunadamente, haremos una pequeña poda de su población."
lang["#MISSION_CHALLENGER_SHREDDEDSCALES_HINT"] = "Elimina cualquier tipo de Gecko. Se pueden encontrar en Salt Wells, o a veces en las carreteras de las Tierras de Ceniza."
lang["#MISSION_CHALLENGER_SHREDDEDSCALES_COMPLETE"] = "Quiero decir, oye, sus pieles son buenas para obtener ganancias."

lang["#MISSION_CHALLENGER_RAIDTHIS"] = "¡Asalta Esto!"
lang["#MISSION_CHALLENGER_RAIDTHIS_DESC"] = "Para este desafío, quiero que vayas por ahí y elimines a cualquier Asaltante o Bandido a la vista. Necesitamos menos de estos imbéciles atacando a los habitantes del yermo."
lang["#MISSION_CHALLENGER_RAIDTHIS_HINT"] = "Elimina cualquier tipo de Bandido. Se pueden encontrar comúnmente en Salt Wells y Yolla Bolly."
lang["#MISSION_CHALLENGER_RAIDTHIS_COMPLETE"] = "¡Sí, asalta esto! Eh, eso sonó un poco raro."

lang["#MISSION_CHALLENGER_SCORPIONSBUTMUTATED"] = "Escorpiones, Pero Mutados"
lang["#MISSION_CHALLENGER_SCORPIONSBUTMUTATED_DESC"] = "¿Alguna vez te ha picado un Escorpión? No, me refiero a los Mutascorpiones. Normalmente llevan veneno, y es probable que mueras en un par de horas o unos días por ello. Por suerte para nosotros, tenemos Stimpaks, y será mejor que te asegures de tener algunos porque cazarlos es tu próximo desafío."
lang["#MISSION_CHALLENGER_SCORPIONSBUTMUTATED_HINT"] = "Elimina cualquier tipo de Mutascorpius. Suelen aparecer detrás de la ciudad, en su propia cueva, o si no, cerca de la gasolinera. Se recomienda usar armas de fuego contra ellos y mantenerse alejado de su aguijón."
lang["#MISSION_CHALLENGER_SCORPIONSBUTMUTATED_COMPLETE"] = "Siempre es mejor tener menos."

lang["#MISSION_CHALLENGER_LOWTIDE"] = "Marea Baja"
lang["#MISSION_CHALLENGER_LOWTIDE_DESC"] = "Probablemente ya hayas visto Mirelurks antes, o no, porque les gusta enterrarse mucho. Ya deberías tener la idea habitual: necesito que los elimines para este desafío. Asegúrate de ir con protección o amigos, o te partirán por la mitad."
lang["#MISSION_CHALLENGER_LOWTIDE_HINT"] = "Elimina cualquier tipo de Mirelurk. Se pueden encontrar cerca de lagos, estanques o ríos. Se recomienda protección o armadura."
lang["#MISSION_CHALLENGER_LOWTIDE_COMPLETE"] = "¡Me alegra verte a ti y a todas tus extremidades!"

lang["#MISSION_CHALLENGER_DEMOLISHED"] = "Demolido"
lang["#MISSION_CHALLENGER_DEMOLISHED_DESC"] = "¿Listo para un desafío más duro? ¿Qué opinas de los Supermutantes? Tenemos montones de ellos aquí."
lang["#MISSION_CHALLENGER_DEMOLISHED_HINT"] = "Elimina Supermutantes en las Tierras de Ceniza. Se pueden encontrar en campamentos alrededor de las Tierras de Ceniza. Los Supermutantes generalmente están armados y son muy peligrosos; se recomienda luchar contra ellos con aliados."
lang["#MISSION_CHALLENGER_DEMOLISHED_COMPLETE"] = "Buen tiro. Estos imbéciles sobredimensionados están por todas partes."

lang["#MISSION_CHALLENGER_GRIMREAVER"] = "Segador Sombrío"
lang["#MISSION_CHALLENGER_GRIMREAVER_DESC"] = "Este desafío no será fácil. Y recomiendo usar un arma potente, porque vas a eliminar Segadores. Estos necrófagos no son para meterse con ellos, son muy peligrosos. No te preocupes, tengo fe en ti. También tengo una recompensa especial para animarte."
lang["#MISSION_CHALLENGER_GRIMREAVER_HINT"] = "Elimina Necrófagos Salvajes Segadores. Se recomienda usar un arma potente."
lang["#MISSION_CHALLENGER_GRIMREAVER_COMPLETE"] = "La mayoría de la gente se habría rendido para entonces. Buen trabajo."

lang["#MISSION_CHALLENGER_ABOMINATION"] = "Abominación"
lang["#MISSION_CHALLENGER_ABOMINATION_DESC"] = "Sanguinarios, ¿has oído hablar de ellos? Abominaciones andantes, y todo lo que hacen es bloquear caminos y atacar intrusos. Bueno, considera esta tu prueba 'final'. Sabes lo que te voy a pedir."
lang["#MISSION_CHALLENGER_ABOMINATION_HINT"] = "Elimina cualquier tipo de Sanguinario. Se recomienda usar rifles automáticos de alta potencia y tener compañeros de equipo. Se pueden encontrar cerca del borde de la ciudad."
lang["#MISSION_CHALLENGER_ABOMINATION_COMPLETE"] = "En realidad, me sorprende que estés vivo."

lang["#MISSION_CHALLENGER_STRESSORI"] = "Estresor, I"
lang["#MISSION_CHALLENGER_STRESSORI_DESC"] = "Oye, Habitante del Yermo. Me alegra ver que todavía respiras por aquí. Todavía necesitamos gente como tú. Je, bueno, ¿estás listo para un verdadero dolor? Tengo una tarea muy difícil para ti esta vez, asegúrate de estar listo para ella."
lang["#MISSION_CHALLENGER_STRESSORI_HINT"] = "Elimina cualquier tipo de Necrófago Salvaje, Gecko y Mirelurk. Los Necrófagos Salvajes se pueden encontrar en ruinas antiguas. Los Geckos se pueden encontrar en áreas genéricas del yermo. Los Mirelurks se pueden encontrar cerca de lagos."
lang["#MISSION_CHALLENGER_STRESSORI_COMPLETE"] = "Buen trabajo, pero no ha terminado todavía."

lang["#MISSION_CHALLENGER_STRESSORII"] = "Estresor, II"
lang["#MISSION_CHALLENGER_STRESSORII_DESC"] = "¿Todavía quieres continuar? No debería llevar mucho tiempo. Solo necesito que extermines algunas plagas."
lang["#MISSION_CHALLENGER_STRESSORII_HINT"] = "Elimina cualquier tipo de Mantis, Mutaracha y Rata Topo. Las Mantis se pueden encontrar en áreas genéricas del yermo. Las Mutarachas se pueden encontrar en áreas recónditas. Las Ratas Topo se pueden encontrar en ubicaciones relacionadas con basura."
lang["#MISSION_CHALLENGER_STRESSORII_COMPLETE"] = "Me alegra ver que te deshiciste de ellas. Tengo una última parte."

lang["#MISSION_CHALLENGER_STRESSORIII"] = "Estresor, III"
lang["#MISSION_CHALLENGER_STRESSORIII_DESC"] = "Esta será la parte más difícil, pero confía en mí, valdrá la pena. Necesito que caces a algunos de los más peligrosos. Probablemente deberías usar un rifle de alta potencia para esto."
lang["#MISSION_CHALLENGER_STRESSORIII_HINT"] = "Elimina cualquier tipo de Sanguinario, Necrófago Salvaje Segador y Gecko Verde. Los Sanguinarios se pueden encontrar comúnmente cerca del borde de la ciudad en las Tierras de Ceniza. Los Necrófagos Salvajes Segadores se pueden encontrar en el hotel o en el búnker de la gasolinera. Los Geckos Verdes se pueden encontrar en áreas genéricas del yermo o en el bosque de las Tierras de Ceniza."
lang["#MISSION_CHALLENGER_STRESSORIII_COMPLETE"] = "Está hecho. Eres diferente a la mayoría de los habitantes del yermo que veo."

-- Varios
lang["#MISSION_CHALLENGER_GOLDENSKIN"] = "Piel Dorada"
lang["#MISSION_CHALLENGER_GOLDENSKIN_DESC"] = "Oye, tengo un tipo diferente de trabajo para ti. Alguien especial me pidió pieles doradas, y ofrece muchas tapas por ellas. Así que si quieres ayudar a obtenerlas, te daré una gran parte de las tapas."
lang["#MISSION_CHALLENGER_GOLDENSKIN_HINT"] = "Obtén Pieles de Gecko Dorado. Se pueden recolectar matando Geckos Dorados, que aparecen más comúnmente en el pantano con el remolque en las Tierras de Ceniza."
lang["#MISSION_CHALLENGER_GOLDENSKIN_COMPLETE"] = "Aquí está tu parte."

RELOADSCHEMA = true